117: func (s *runtimeState) runtimeErrors() error {
118: 	s.RLock()
119: 	defer s.RUnlock()
120: 	errs := []error{}
121: 	if s.lastBaseRuntimeSync.IsZero() {
122: 		errs = append(errs, errors.New("container runtime status check may not have completed yet"))
123: 	} else if !s.lastBaseRuntimeSync.Add(s.baseRuntimeSyncThreshold).After(time.Now()) {
124: 		errs = append(errs, errors.New("container runtime is down"))
125: 	}
126: 	for _, hc := range s.healthChecks {
127: 		if ok, err := hc.fn(); !ok {
128: 			errs = append(errs, fmt.Errorf("%s is not healthy: %v", hc.name, err))
129: 		}
130: 	}
131: 	if s.runtimeError != nil {
132: 		errs = append(errs, s.runtimeError)
133: 	}
134: 
135: 	return utilerrors.NewAggregate(errs)
136: }
