139: 	s.RLock()
140: 	defer s.RUnlock()
141: 	errs := []error{}
142: 	if s.networkError != nil {
143: 		errs = append(errs, s.networkError)
144: 	}
145: 	return utilerrors.NewAggregate(errs)
146: }
